-- =============================================================================
-- LANDING TABLE: L_PO_LINES_BC
-- =============================================================================
-- COPY_DATA loads the raw CSV into this table.
-- The load procedure then cherry-picks columns into stg_fbx_po_lines.
--
-- SETUP (two steps):
--   1. Create the external table (defines the CSV structure)
--   2. Create the landing table as a copy of the external table structure
--
-- IF BICC SCHEMA CHANGES:
--   DROP TABLE L_PO_LINES_BC;
--   DROP TABLE EXT_PO_LINES_BC;
--   Re-run Step 1 with updated column_list, then re-run Step 2.
-- =============================================================================


-- Step 1: Create external table (one-time, defines CSV structure)
-- This is the source of truth for column names and order.
-- UPDATE the file_uri_list to point at an existing extracted CSV before running.
BEGIN
  DBMS_CLOUD.CREATE_EXTERNAL_TABLE(
    table_name      => 'EXT_PO_LINES_BC',
    credential_name => '<OCI_CREDENTIAL_NAME>',
    file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/<OCI_NAMESPACE>/b/<OCI_BUCKET_NAME>/o/po_lines_extracted.csv',
    format          => json_object(
                         'type' value 'csv',
                         'skipheaders' value '1'
                       ),
    column_list     => 'AGINGPERIODDAYS VARCHAR2(4000),ALLOWDESCRIPTIONUPDATEFLAG VARCHAR2(4000),ALLOWPRICEOVERRIDEFLAG VARCHAR2(4000),AMOUNT VARCHAR2(4000),AMOUNTRELEASED VARCHAR2(4000),AUCTIONDISPLAYNUMBER VARCHAR2(4000),AUCTIONHEADERID VARCHAR2(4000),AUCTIONLINENUMBER VARCHAR2(4000),BASEMODELID VARCHAR2(4000),BASEMODELPRICE VARCHAR2(4000),BASEQTY VARCHAR2(4000),BASEUNITPRICE VARCHAR2(4000),BASEUOM VARCHAR2(4000),BIDLINENUMBER VARCHAR2(4000),BIDNUMBER VARCHAR2(4000),CANCELDATE VARCHAR2(4000),CANCELFLAG VARCHAR2(4000),CANCELREASON VARCHAR2(4000),CANCELLEDBY VARCHAR2(4000),CAPITALEXPENSEFLAG VARCHAR2(4000),CATEGORYID VARCHAR2(4000),CLOSEDBY VARCHAR2(4000),CLOSEDDATE VARCHAR2(4000),CLOSEDREASON VARCHAR2(4000),COMMITTEDAMOUNT VARCHAR2(4000),CONFIGUREDITEMFLAG VARCHAR2(4000),CONSIGNMENTLINEFLAG VARCHAR2(4000),CONTRACTID VARCHAR2(4000),CONTRACTORFIRSTNAME VARCHAR2(4000),CONTRACTORLASTNAME VARCHAR2(4000),CREATEDBY VARCHAR2(4000),CREATIONDATE VARCHAR2(4000),DISCOUNT VARCHAR2(4000),DISCOUNTREASON VARCHAR2(4000),DISCOUNTTYPE VARCHAR2(4000),EXPIRATIONDATE VARCHAR2(4000),FROMHEADERID VARCHAR2(4000),FROMLINEID VARCHAR2(4000),FROMLINELOCATIONID VARCHAR2(4000),FUNDSSTATUS VARCHAR2(4000),HAZARDCLASSID VARCHAR2(4000),ITEMDESCRIPTION VARCHAR2(4000),ITEMID VARCHAR2(4000),ITEMREVISION VARCHAR2(4000),JOBID VARCHAR2(4000),LASTUPDATEDATE VARCHAR2(4000),LASTUPDATELOGIN VARCHAR2(4000),LASTUPDATEDBY VARCHAR2(4000),LASTUPDATEDPROGRAM VARCHAR2(4000),LINENUM VARCHAR2(4000),LINEREFERENCENUM VARCHAR2(4000),LINESTARTDATE VARCHAR2(4000),LINESTATUS VARCHAR2(4000),LINETYPEID VARCHAR2(4000),LISTPRICE VARCHAR2(4000),LISTPRICEPERUNIT VARCHAR2(4000),MANUALPRICECHANGEFLAG VARCHAR2(4000),MANUFACTURER VARCHAR2(4000),MANUFACTURERPARTNUM VARCHAR2(4000),MARKETPRICE VARCHAR2(4000),MATCHINGBASIS VARCHAR2(4000),MAXRETAINAGEAMOUNT VARCHAR2(4000),MINRELEASEAMOUNT VARCHAR2(4000),NEGOTIATEDBYPREPARERFLAG VARCHAR2(4000),NEXTCONSUMPTIONADVGENDATE VARCHAR2(4000),NOTTOEXCEEDPRICE VARCHAR2(4000),NOTETOVENDOR VARCHAR2(4000),OBJECTVERSIONNUMBER VARCHAR2(4000),OKECONTRACTHEADERID VARCHAR2(4000),OKECONTRACTVERSIONID VARCHAR2(4000),OPTIONSPRICE VARCHAR2(4000),ORDERTYPELOOKUPCODE VARCHAR2(4000),OVERTOLERANCEERRORFLAG VARCHAR2(4000),PARENTITEMID VARCHAR2(4000),PJCBUBIGDECIMAL VARCHAR2(4000),POHEADERID VARCHAR2(4000),POLINEID VARCHAR2(4000),PRCBUID VARCHAR2(4000),PRICEBREAKLOOKUPCODE VARCHAR2(4000),PRICETYPELOOKUPCODE VARCHAR2(4000),PURCHASEBASIS VARCHAR2(4000),QTYRCVTOLERANCE VARCHAR2(4000),QUANTITY VARCHAR2(4000),QUANTITYCOMMITTED VARCHAR2(4000),REQBUID VARCHAR2(4000),REQUESTID VARCHAR2(4000),RETROACTIVEDATE VARCHAR2(4000),SECONDARYQUANTITY VARCHAR2(4000),SECONDARYUOMCODE VARCHAR2(4000),SHIPPINGUOMCODE VARCHAR2(4000),SHIPPINGUOMQUANTITY VARCHAR2(4000),SOURCEDOCREVNUM VARCHAR2(4000),STARTDATE VARCHAR2(4000),SUPPLIERPARENTITEM VARCHAR2(4000),SUPPLIERPARTAUXID VARCHAR2(4000),SUPPLIERREFNUMBER VARCHAR2(4000),SUPPLIERTOPMODEL VARCHAR2(4000),TAXATTRIBUTEUPDATECODE VARCHAR2(4000),TAXCODEID VARCHAR2(4000),TAXEXCLUSIVEPRICE VARCHAR2(4000),TAXNAME VARCHAR2(4000),TAXABLEFLAG VARCHAR2(4000),TOPMODELID VARCHAR2(4000),UNNUMBERID VARCHAR2(4000),UNITPRICE VARCHAR2(4000),UNORDEREDFLAG VARCHAR2(4000),UOMCODE VARCHAR2(4000),VENDORPRODUCTNUM VARCHAR2(4000),WORKORDERPRODUCT VARCHAR2(4000)'
  );
END;
/

-- Step 2: Create landing table from external table structure (empty copy)
CREATE TABLE L_PO_LINES_BC AS
SELECT * FROM EXT_PO_LINES_BC WHERE 1=0;
